class Solution:
    def heapifyInsertion(self, maxHeap, number):
        maxHeap.append(number);
        i = len(maxHeap) - 1;
        while i > 0:
            parent = Math.floor((i - 1) / 2);
            if maxHeap[parent] > maxHeap[i]:
                break;
            else:
                maxHeap[parent], maxHeap[i] = maxHeap[i], maxHeap[parent];
                i = parent;
        return maxHeap;

    def readInput(self):
        n = int(input());
        maxHeap = [];
        for i in range(n):
            number = int(input());
            maxHeap.append(number);

        number = int(input());
        return maxHeap, number;

    def printOutput(self, maxHeap, number):
        print(maxHeap);


if __name__ == '__main__':
    solution = Solution();
    maxHeap, number = solution.readInput();
    result = solution.heapifyInsertion(maxHeap, number);
    solution.printOutput(result, number);

