#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
    vector<int> heapifyInsertion(vector<int> maxHeap, int number)
    {
        maxHeap.push_back(number);
        int i = maxHeap.size() - 1;
        while (i > 0) {
            int parent = (i - 1) / 2;
            if (maxHeap[parent] > maxHeap[i]) {
                break;
            } else {
                swap(maxHeap[parent], maxHeap[i]);
                i = parent;
            }
        }
        return maxHeap;
    }
};

